import React, { useState, useEffect } from 'react';
import { Sun, Moon, Home, Layers, Code, Mail } from 'lucide-react';
import { NAV_ITEMS } from '../constants';

interface NavigationProps {
  isDark: boolean;
  toggleTheme: () => void;
}

export const Navigation: React.FC<NavigationProps> = ({ isDark, toggleTheme }) => {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToSection = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    e.preventDefault();
    const element = document.querySelector(href);
    if (element) {
      const offset = 100;
      const bodyRect = document.body.getBoundingClientRect().top;
      const elementRect = element.getBoundingClientRect().top;
      const elementPosition = elementRect - bodyRect;
      const offsetPosition = elementPosition - offset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  return (
    <>
      <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        isScrolled ? 'bg-white/80 dark:bg-deep-950/80 backdrop-blur-xl py-4 border-b border-slate-200 dark:border-white/5' : 'bg-transparent py-8'
      }`}>
        <div className="max-w-7xl mx-auto px-6 lg:px-12 flex justify-between items-center">
          <a href="#" onClick={(e) => scrollToSection(e, '#hero')} className="text-xl font-serif font-black tracking-tighter text-slate-950 dark:text-white">
            Muhammad Al-amin<span className="text-brand-600">.</span>
          </a>

          <div className="hidden md:flex items-center space-x-10">
            {NAV_ITEMS.map((item) => (
              <a
                key={item.label}
                href={item.href}
                onClick={(e) => scrollToSection(e, item.href)}
                className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-500 hover:text-brand-600 dark:text-slate-400 dark:hover:text-brand-500 transition-colors"
              >
                {item.label}
              </a>
            ))}
            <button 
              onClick={toggleTheme} 
              className="p-2.5 bg-slate-100 dark:bg-white/5 rounded-full hover:bg-brand-600 hover:text-white transition-all shadow-sm"
              aria-label="Toggle Theme"
            >
              {isDark ? <Sun size={18} /> : <Moon size={18} />}
            </button>
          </div>

          <div className="md:hidden flex items-center">
             <button onClick={toggleTheme} className="p-2.5 bg-slate-100 dark:bg-white/5 rounded-full">
                {isDark ? <Sun size={18} /> : <Moon size={18} />}
             </button>
          </div>
        </div>
      </nav>

      {/* Mobile Floating App Bar */}
      <div className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 z-50 w-[90%] max-w-sm">
        <div className="glass bg-white/90 dark:bg-deep-950/90 border border-slate-200 dark:border-white/10 rounded-[2rem] p-2 flex justify-between items-center shadow-2xl">
          <a href="#hero" onClick={(e) => scrollToSection(e, '#hero')} className="flex-1 flex justify-center py-3 text-brand-600 bg-brand-50/50 dark:bg-brand-900/20 rounded-2xl">
            <Home size={20} />
          </a>
          <a href="#services" onClick={(e) => scrollToSection(e, '#services')} className="flex-1 flex justify-center py-3 text-slate-400">
            <Layers size={20} />
          </a>
          <a href="#work" onClick={(e) => scrollToSection(e, '#work')} className="flex-1 flex justify-center py-3 text-slate-400">
            <Code size={20} />
          </a>
          <a href="#contact" onClick={(e) => scrollToSection(e, '#contact')} className="flex-1 flex justify-center py-3 text-slate-400">
            <Mail size={20} />
          </a>
        </div>
      </div>
    </>
  );
};

