import React, { createContext, useContext, useState, useEffect } from 'react';

export type ThemeType = 'default' | 'ocean' | 'sunset' | 'forest' | 'cyber';
export type ModeType = 'light' | 'dark';

interface ThemeContextType {
  theme: ThemeType;
  setTheme: (t: ThemeType) => void;
  mode: ModeType;
  toggleMode: () => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setThemeState] = useState<ThemeType>('default');
  const [mode, setModeState] = useState<ModeType>('light');

  useEffect(() => {
    const savedTheme = localStorage.getItem('site-theme-selection') as ThemeType;
    const savedMode = localStorage.getItem('site-mode-selection') as ModeType;

    if (savedTheme) {
      setThemeState(savedTheme);
      document.documentElement.setAttribute('data-theme', savedTheme);
    }
    if (savedMode) {
      setModeState(savedMode);
      document.documentElement.setAttribute('data-mode', savedMode);
      if (savedMode === 'dark') document.documentElement.classList.add('dark');
    } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setModeState('dark');
      document.documentElement.setAttribute('data-mode', 'dark');
      document.documentElement.classList.add('dark');
    }
  }, []);

  const setTheme = (newTheme: ThemeType) => {
    setThemeState(newTheme);
    localStorage.setItem('site-theme-selection', newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
  };

  const toggleMode = () => {
    const newMode = mode === 'light' ? 'dark' : 'light';
    setModeState(newMode);
    localStorage.setItem('site-mode-selection', newMode);
    document.documentElement.setAttribute('data-mode', newMode);
    if (newMode === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  return (
    <ThemeContext.Provider value={{ theme, setTheme, mode, toggleMode }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within a ThemeProvider');
  return context;
};

