import React, { createContext, useContext, useState, useEffect } from 'react';

export type LanguageType = 'en' | 'bn';
export type ModeType = 'light' | 'dark';
// Added ThemeType to support color skin selection as required by ThemeSelector
export type ThemeType = 'default' | 'ocean' | 'sunset' | 'forest' | 'cyber';

interface ThemeContextType {
  language: LanguageType;
  setLanguage: (l: LanguageType) => void;
  mode: ModeType;
  toggleMode: () => void;
  // Added theme and setTheme to the context interface to fix errors in components/ThemeSelector.tsx
  theme: ThemeType;
  setTheme: (t: ThemeType) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLangState] = useState<LanguageType>('en');
  const [mode, setModeState] = useState<ModeType>('light');
  // New state for theme skin management
  const [theme, setThemeState] = useState<ThemeType>('default');

  useEffect(() => {
    const savedLang = localStorage.getItem('user-language') as LanguageType;
    const savedMode = localStorage.getItem('user-mode') as ModeType;
    const savedTheme = localStorage.getItem('user-theme') as ThemeType;

    if (savedLang) {
      setLangState(savedLang);
      document.documentElement.setAttribute('data-language', savedLang);
    }

    if (savedMode) {
      setModeState(savedMode);
      document.documentElement.setAttribute('data-mode', savedMode);
      if (savedMode === 'dark') document.documentElement.classList.add('dark');
    } else if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
      setModeState('dark');
      document.documentElement.setAttribute('data-mode', 'dark');
      document.documentElement.classList.add('dark');
    }

    // Persist and apply the selected theme skin on initialization
    if (savedTheme) {
      setThemeState(savedTheme);
      document.documentElement.setAttribute('data-theme', savedTheme);
    } else {
      document.documentElement.setAttribute('data-theme', 'default');
    }
  }, []);

  const setLanguage = (l: LanguageType) => {
    setLangState(l);
    localStorage.setItem('user-language', l);
    document.documentElement.setAttribute('data-language', l);
  };

  const toggleMode = () => {
    const newMode = mode === 'light' ? 'dark' : 'light';
    setModeState(newMode);
    localStorage.setItem('user-mode', newMode);
    document.documentElement.setAttribute('data-mode', newMode);
    if (newMode === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  // Implementation of setTheme to handle state updates and DOM attribute updates for styling
  const setTheme = (t: ThemeType) => {
    setThemeState(t);
    localStorage.setItem('user-theme', t);
    document.documentElement.setAttribute('data-theme', t);
  };

  return (
    <ThemeContext.Provider value={{ language, setLanguage, mode, toggleMode, theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within a ThemeProvider');
  return context;
};

