  const [isPaletteOpen, setIsPaletteOpen] = useState(false);
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [currentLangCode, setCurrentLangCode] = useState(() => {
    // Initial check from cookie
    const match = document.cookie.match(/googtrans=\/en\/([^;]+)/);
    return match ? match[1] : 'en';
  });

  const paletteRef = useRef<HTMLDivElement>(null);
  const langRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    const handleClickOutside = (e: MouseEvent) => {
      if (paletteRef.current && !paletteRef.current.contains(e.target as Node)) {
        setIsPaletteOpen(false);
      }
      if (langRef.current && !langRef.current.contains(e.target as Node)) {
        setIsLangOpen(false);
      }
    };
    window.addEventListener('scroll', handleScroll);
    document.addEventListener('mousedown', handleClickOutside);

    // Sync UI with current applied lang on mount
    document.documentElement.setAttribute('data-applied-lang', currentLangCode);

    return () => {
      window.removeEventListener('scroll', handleScroll);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [currentLangCode]);

  const changeLanguage = (langCode: string) => {
    setCurrentLangCode(langCode);
    setIsLangOpen(false);

    // 1. Critical: Set the cookie first (Google Translate reads this)
    const domain = window.location.hostname === 'localhost' ? '' : `; domain=.${window.location.hostname}`;
    document.cookie = `googtrans=/en/${langCode}; path=/;${domain}`;
    document.cookie = `googtrans=/en/${langCode}; path=/;`; // Also set for the current path

    // 2. Update font styling
    document.documentElement.setAttribute('data-applied-lang', langCode);

    // 3. Trigger the hidden combo box if it exists
    const performTranslation = () => {
      const combo = document.querySelector('.goog-te-combo') as HTMLSelectElement;
      if (combo) {
        combo.value = langCode;
        combo.dispatchEvent(new Event('change'));
      }
    };

    performTranslation();

    // 4. Handle English reset specifically
    if (langCode === 'en') {
      document.cookie = 'googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;';
      if (window.location.hostname !== 'localhost') {
        document.cookie = `googtrans=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; domain=.${window.location.hostname};`;
      }
      window.location.reload(); // Best way to clear Google's messy DOM changes for English
    } else {
      // Re-trigger after a few moments to ensure Google Translate caught the change
      setTimeout(performTranslation, 500);
      setTimeout(performTranslation, 1500);
    }
